prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "4ccc3fd711004f519782ac92e58f6ddd" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "4ccc3fd711004f519782ac92e58f6ddd") ||
         CONTAINS(LCASE(STR(?originalId)), "4ccc3fd711004f519782ac92e58f6ddd") ||
         CONTAINS(LCASE(STR(?normalizedId)), "4ccc3fd711004f519782ac92e58f6ddd"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?def ?choreo ?taskCount ?eventCount ?gatewayCount ?flowCount WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?def tai:belongsTo ?model .
  ?def a bboExt:Definitions .
  ?choreo tai:belongsTo ?def .
  ?choreo a bboExt:Choreography .
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?event) AS ?eventCount) WHERE {
      ?event a bbo:FlowNode .
      ?event tai:belongsTo ?choreo .
      FILTER(?event a bboExt:StartEvent || ?event a bboExt:EndEvent || ?event a bboExt:IntermediateCatchEvent)
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?gw) AS ?gatewayCount) WHERE {
      ?gw a bbo:FlowNode .
      ?gw tai:belongsTo ?choreo .
      FILTER(?gw a bboExt:ExclusiveGateway || ?gw a bboExt:ParallelGateway || ?gw a bboExt:EventBasedGateway)
    } GROUP BY ?choreo
  }
  OPTIONAL {
    SELECT ?choreo (COUNT(DISTINCT ?flow) AS ?flowCount) WHERE {
      ?flow a bbo:SequenceFlow .
      ?flow tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sourceName ?edgeName ?targetName ?flowType WHERE {
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> .
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { ?edge bbo:name ?edgeName . }
}
ORDER BY ?sourceName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?participant ?pName ?multMin ?multMax WHERE {
  ?participant tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> .
  ?participant a bboExt:Participant .
  OPTIONAL { ?participant bbo:name ?pName . }
  OPTIONAL { 
    ?mult a bboExt:ParticipantMultiplicity .
    ?mult tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> .
    ?mult bbo:participantRef ?participant .
    OPTIONAL { ?mult bboExt:minimum ?multMin . }
    OPTIONAL { ?mult bboExt:maximum ?multMax . }
  }
}
ORDER BY ?pName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?initPartRef WHERE {
